changeSet.sql:
CREATE TABLE IF NOT EXISTS customer (
                          id uuid PRIMARY KEY,
                          name varchar(200) NOT NULL,
                          inn varchar(20) NOT NULL,
                          kpp varchar(50)
);

CREATE TABLE IF NOT EXISTS user_customer_link (
                                    id uuid PRIMARY KEY,
                                    user_id uuid NOT NULL,
                                    customer_id uuid NOT NULL,
                                    FOREIGN KEY (customer_id) REFERENCES customer(id),
                                    FOREIGN KEY (user_id) REFERENCES system_users(id)
);

CREATE INDEX IF NOT EXISTS idx_user_customer_link_user_id ON user_customer_link(user_id);
CREATE INDEX IF NOT EXISTS idx_user_customer_link_customer_id ON user_customer_link(customer_id);

CREATE TABLE IF NOT EXISTS address (
                         id uuid PRIMARY KEY,
                         customer_id uuid NOT NULL,
                         name varchar(1000),
                         FOREIGN KEY (customer_id) REFERENCES customer(id)
);

CREATE INDEX IF NOT EXISTS idx_address_customer_id ON address(customer_id);

CREATE TABLE IF NOT EXISTS supplier (
                          id uuid PRIMARY KEY,
                          name varchar(100) NOT NULL
);

CREATE TABLE IF NOT EXISTS customer_external_id (
                                      id uuid PRIMARY KEY,
                                      customer_id uuid NOT NULL,
                                      supplier_id uuid NOT NULL,
                                      customer_external_id uuid NOT NULL,

                                      CONSTRAINT uq_customer_external_id_customer_supplier UNIQUE (customer_id, supplier_id),

                                      FOREIGN KEY (customer_id) REFERENCES customer(id),
                                      FOREIGN KEY (supplier_id) REFERENCES supplier(id)
);

CREATE INDEX IF NOT EXISTS idx_customer_external_id_customer_id ON customer_external_id(customer_id);
CREATE INDEX IF NOT EXISTS idx_customer_external_id_supplier_id ON customer_external_id(supplier_id);

CREATE TABLE IF NOT EXISTS nomenclature ( id uuid PRIMARY KEY, code varchar(50) NOT NULL, name varchar(255) NOT NULL, supplier_id uuid NOT NULL, FOREIGN KEY (supplier_id) REFERENCES supplier(id) );
CREATE TABLE IF NOT EXISTS price_positions ( id uuid PRIMARY KEY, price_id uuid NOT NULL, nomenclature_id uuid NOT NULL, unit_measure varchar(20), price_with_vat float NOT NULL, vat BIGINT NOT NULL,
CONSTRAINT uq_price_positions_price_nomenclature UNIQUE (price_id, nomenclature_id), FOREIGN KEY (nomenclature_id) REFERENCES nomenclature(id), FOREIGN KEY (price_id) REFERENCES price_list(id) );
